import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"移植到 1.21.11","description":"移植到 Minecraft 最新版本的指南。","frontmatter":{"title":"移植到 1.21.11","description":"移植到 Minecraft 最新版本的指南。","authors":["cassiancc"],"files":[]},"headers":[],"relativePath":"zh_cn/develop/porting/current.md","filePath":"translated/zh_cn/develop/porting/current.md","lastUpdated":1772272927000}`);var a={name:`zh_cn/develop/porting/current.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">移植到 1.21.11 <a class="header-anchor" href="#h1" aria-label="Permalink to “移植到 1.21.11”">​</a></h1><p>Minecraft 是不断发展中的游戏，新的版本改变游戏的同时也会影响模组开发者。 本文章包含了将模组更新到最新的 Minecraft 稳定版本需要遵循的通用步骤。</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>这些文档讨论的是从 <strong>1.21.10</strong> 迁移到 <strong>1.21.11</strong>， 如果在找其他的迁移，使用右上角的下拉菜单切换到目标版本。</p></div><h2 id="build-script" tabindex="-1">更新构建脚本 <a class="header-anchor" href="#build-script" aria-label="Permalink to “更新构建脚本”">​</a></h2><p>首先将你的模组的 <code>gradle/wrapper/gradle-wrapper.properties</code>、<code>gradle.properties</code> 和 <code>build.gradle</code> 更新到最新版本：</p><ol><li>运行以下命令，将 Gradle 更新到最新版：<code>./gradlew wrapper --gradle-version latest</code></li><li>在 <code>gradle.properties</code>（推荐）或 <code>build.gradle</code> 中找到 Minecraft、Fabric Loader、Fabric Loom 和 Fabric API 的版本。 在 <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">Fabric Develop 网站</a>找到 Fabric 组件的推荐版本。</li><li>按 IntelliJ IDEA 右上角的刷新按钮刷新 Gradle。 如果按钮不可见，可运行 <code>./gradlew --refresh-dependencies</code> 以强制清除缓存。</li></ol><h2 id="porting-guides" tabindex="-1">更新代码 <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “更新代码”">​</a></h2><p>构建脚本更新到 1.21.11 后，现在就可以检查你的模组并更新任何改变的代码，以使其与新版本兼容。</p><p>为帮助你更新，模组开发者会在文章中记下他们遇到的变更，例如 Fabric Blog 和 NeoForge 的 porting primer。</p><ul><li><a href="https://fabricmc.net/2025/12/05/12111.html" target="_blank" rel="noreferrer">Fabric blog 上的 <em>Fabric for Minecraft 1.21.11</em></a> 包含对 Fabric API 1.21.11 版本所做更改的概述。</li><li><a href="https://www.minecraft.net/en-us/article/minecraft-java-edition-1-21-11" target="_blank" rel="noreferrer">Minecraft blog 上的 <em>Minecraft: Java Edition 1.21.11</em></a> 是 1.21.11 引入的功能的官方概览。</li><li><a href="https://zh.minecraft.wiki/w/Java%E7%89%881.21.11" target="_blank" rel="noreferrer">Minecraft Wiki 上的《Java版1.21.11》</a>是此次更新内容的非官方总结。</li><li>YouTube 上的 <a href="https://www.youtube.com/watch?v=5yY25GoWQhs&amp;pp=0gcJCSkKAYcqIYzv" target="_blank" rel="noreferrer">slicedlime 的 Data &amp; Resource Pack News in Minecraft 1.21.11</a> 介绍了与更新模组的数据和资源包驱动内容相关的信息。</li><li><a href="https://github.com/neoforged/.github/blob/main/primers/1.21.11/index.md" target="_blank" rel="noreferrer">NeoForge 的 <em>Minecraft 1.21.10 -&gt; 1.21.11 Mod Migration Primer</em></a> 介绍了从 1.21.10 迁移到 1.21.11，仅聚焦于原版代码的变更。 <ul><li>请注意，链接的文章是第三方材料，不由 Fabric 维护。 其版权属于 @ChampionAsh5357，按 <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a> 的许可协议发布。</li></ul></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};